"""Извлечение YAML frontmatter из markdown-текста и сборка markdown из модели."""from __future__ import annotationsfrom typing import TYPE_CHECKINGimport yamlif TYPE_CHECKING:    from src.modules.markdown.models import MarkdownDocumentdef extract_markdown_yaml(text: str) -> dict | None:    """    Извлекает YAML-фронтматтер из начала текста (формат ---\\n...\\n---).    :param text: Исходный текст (markdown с опциональным frontmatter).    :return: Словарь параметров, если разметка есть; пустой словарь, если разметка есть,             но пустая; None, если разметки нет или она невалидна.    """    if not text or not text.strip():        return None    stripped = text.lstrip()    if not stripped.startswith("---"):        return None    rest = stripped[3:].lstrip("\n")    if rest.startswith("---"):        return {}    end = rest.find("\n---")    if end == -1:        return None    yaml_block = rest[:end].strip()    if not yaml_block:        return {}    try:        data = yaml.safe_load(yaml_block)    except yaml.YAMLError:        return None    if data is None:        return {}    if not isinstance(data, dict):        return None    return datadef _frontmatter_tail(text: str) -> tuple[str, str] | None:    """    Если в начале text есть frontmatter (---\\n...\\n---), возвращает (leading_ws, body).    Иначе None.    """    if not text or not text.strip():        return None    stripped = text.lstrip()    if not stripped.startswith("---"):        return None    prefix_ws = text[: len(text) - len(stripped)]    rest = stripped[3:].lstrip("\n")    if rest.startswith("---"):        return (prefix_ws, rest[3:].lstrip("\n"))    end = rest.find("\n---")    if end == -1:        return None    body = rest[end + 4 :].lstrip("\n")  # после "\n---"    return (prefix_ws, body)def clear_markdown_yaml(text: str) -> str:    """    Удаляет YAML-фронтматтер из начала текста (блок ---\\n...\\n---).    :param text: Исходный текст (markdown с опциональным frontmatter).    :return: Текст без блока frontmatter; если разметки нет — исходный текст без изменений.    """    pair = _frontmatter_tail(text)    if pair is None:        return text    return pair[0] + pair[1]def build_markdown_from_document(doc: MarkdownDocument) -> str:    """    Собирает итоговый markdown из полей модели: frontmatter (name, description, date, tags) + тело.    """    body = clear_markdown_yaml(doc.markdown or "").lstrip("\n")    front: dict[str, object] = {}    if doc.name:        front["name"] = doc.name    if doc.description:        front["description"] = doc.description    if doc.date:        front["date"] = doc.date    if doc.tags:        front["tags"] = doc.tags    if not front:        return doc.markdown or ""    yaml_block = yaml.safe_dump(        front,        allow_unicode=True,        sort_keys=False,        default_flow_style=False,    ).strip()    return f"---\n{yaml_block}\n---\n\n{body}"